// ── Pick best media items across all places ──────────────────────────────
// Target: 5-6 clips total for an 18-22 second reel
// Strategy: prefer 1 video per place (better motion), then fill with images

const data = $input.first().json;
const places = data.places || [];

const pendingData = $('Get Next Pending Row').first().json;
const TARGET_ITEMS = 6;
const TARGET_DURATION_SECS = 20; // aim for 18-22s

const picked = [];

// Pass 1: one video per place
for (const place of places) {
  if (picked.length >= TARGET_ITEMS) break;
  const media = place.media || [];
  const video = media.find(m => m.type === 'video' && m.url);
  if (video) {
    picked.push({
      source: 'url',
      url: video.url,
      media_type: 'video',
      title: place.name,
      caption_text: place.caption_text || '',
    });
  }
}

// Pass 2: fill remaining slots with images (best-ranked first)
for (const place of places) {
  if (picked.length >= TARGET_ITEMS) break;
  const media = place.media || [];
  const alreadyPickedUrls = new Set(picked.map(p => p.url));
  for (const item of media) {
    if (picked.length >= TARGET_ITEMS) break;
    if (item.type === 'image' && item.url && !alreadyPickedUrls.has(item.url)) {
      picked.push({
        source: 'url',
        url: item.url,
        media_type: 'image',
        title: place.name,
        caption_text: place.caption_text || '',
      });
      alreadyPickedUrls.add(item.url);
    }
  }
}

if (picked.length === 0) {
  throw new Error('No media items found in travel-media response');
}

// Calculate clip durations to hit ~20s total
const videoCount = picked.filter(p => p.media_type === 'video').length;
const imageCount = picked.filter(p => p.media_type === 'image').length;
let totalEstimated = videoCount * 5 + imageCount * 3;
let clipVideo = 5;
let clipImage = 3;
if (totalEstimated < 18) {
  const scale = TARGET_DURATION_SECS / Math.max(totalEstimated, 1);
  clipVideo = Math.round(5 * scale * 10) / 10;
  clipImage = Math.round(3 * scale * 10) / 10;
} else if (totalEstimated > 22) {
  const scale = TARGET_DURATION_SECS / totalEstimated;
  clipVideo = Math.round(5 * scale * 10) / 10;
  clipImage = Math.round(3 * scale * 10) / 10;
}

return [{
  json: {
    picked_items: picked,
    clip_seconds_video: String(clipVideo),
    clip_seconds_image: String(clipImage),
    total_items: picked.length,
    estimated_duration_secs: videoCount * clipVideo + imageCount * clipImage,
    row_index: pendingData.row_index,
    destination: pendingData.destination,
  }
}];

const dest = $('Get Next Pending Row').first().json.destination || 'unknown';
console.log(`No pending rows in reels-queue.xlsx. All done or queue is empty.`);
return [{ json: { status: 'no_pending', message: 'Queue is empty — nothing to process.', destination: dest } }];
